.darma-loader-darma-custom-404 {color: var(--loader-color, #e11d48);
  width: 50px;
  aspect-ratio: 1;
  border-radius: 50%;
  background:radial-gradient(farthest-side,currentColor 98%,#0000) 55% 20%/8px 8px no-repeat,#ffcc00;
  box-shadow: 2px -6px 12px 0px inset color-mix(in srgb, currentColor 70%, transparent);
  animation: darma-loader-darma-custom-404-l4 .5s infinite steps(5) alternate;
}@keyframes darma-loader-darma-custom-404-l4{0% {clip-path: polygon(50% 50%,100% 0,100% 0,0 0,0 100%,100% 100%,100% 100%)}100% {clip-path: polygon(50% 50%,100% 65%,100% 0,0 0,0 100%,100% 100%,100% 35%)}}

